class Solution:
    def findLengthOfShortestSubarray(self, arr):
        n = len(arr)
        best = n
        for i in range(n + 1):
            for j in range(i, n + 1):
                remaining = arr[:i] + arr[j:]
                ok = all(remaining[k] <= remaining[k + 1] for k in range(len(remaining) - 1))
                if ok:
                    best = min(best, j - i)
        return best

