class Solution:
    def findLengthOfShortestSubarray(self, arr):
        n = len(arr)
        left = 0
        while left + 1 < n and arr[left] <= arr[left + 1]:
            left += 1
        if left == n - 1:
            return 0
        right = n - 1
        while right - 1 >= 0 and arr[right - 1] <= arr[right]:
            right -= 1
        result = min(n - 1 - left, right)
        i, j = 0, right
        while i <= left and j <= n - 1:
            if arr[i] <= arr[j]:
                result = min(result, j - i - 1)
                i += 1
            else:
                j += 1
        return result

